<template>
  <div class="footer" v-show="getFooterEnabled === true">
    <div class="footer-subtitles__wrapper" :style="subtitlesBackgroundStyle">
      <div class="footer-subtitles__text">
        <SubtitlesController />
      </div>
      <div class="footer-subtitles__abort-talk" @click="mute"><span :style="abortIconStyle" class="microphone"></span><span class="right-text">Прервать</span></div>
    </div>
  </div>
</template>

<script>
import { mapGetters, mapActions } from 'vuex'
import SubtitlesController from '@/components/SubtitlesController'

export default {
  name: 'footer-component',
  components: {
    SubtitlesController
  },
  computed: {
    ...mapGetters('robot', [
      'getDialogQuestion'
    ]),
    ...mapGetters('app', [
      'getStep',
      'getLoadAppSettings'
    ]),
    ...mapGetters('ui', [
      'getFooterEnabled'
    ]),
    subtitlesBackgroundStyle () {
      return this.getLoadAppSettings ? { ...this.getLoadAppSettings.subtitlesBackground } : { backgroundColor: '#FAFAFA' }
    },
    abortIconStyle () {
      return this.getLoadAppSettings ? { ...this.getLoadAppSettings.iconAbortReplic } : { backgroundColor: 'rgb(157, 201, 0)' }
    }
  },
  methods: {
    ...mapActions('engine', [
      'handlerClickMoveToState'
    ]),
    ...mapActions('robot', [
      'clickAnswer'
    ]),
    ...mapActions('robot', [
      'abortRobotReplic'
    ]),
    mute () {
      this.abortRobotReplic()
    },
    doAction (action) {
      if (action.type === 'action') {
        this.$store.dispatch(action.data.dispatch, { data: action.data.data })
      }

      if (action.type === 'state') {
        this.handlerClickMoveToState({
          transition: action.data,
          data: action.data
        })
      }
    }
  }
}
</script>

