<template>
  <div class="header" v-show="getHeaderEnabled === true" @click="resetLocalStorage($event)">
<!--    <div class="topLine" :style="topLineStyle"></div>-->
    <div class="headerData" :data-startHeader="getHeaderBtnLeftPhoto" v-show="getHeaderEnabledPodHeader === true">
      <div>
        <div class="headerPhoto" v-show="getHeaderBtnLeftPhoto === true" :style="[{ 'background-image': `url(${ getFaceRecognizeGeneralFrame })` }]"></div>
        <p class="userName" v-if="getHeaderBtnLeftPhoto === true && getUserGet !== null && getUserGet.name">{{ getUserGet.name }}</p>
        <button v-if="getLoadAppSettings" v-show="getHeaderBtnLeftEnabled === true" class="btn btn_header" v-text="getHeaderBtnLeftText" @click="bntAction" :style="{...getLoadAppSettings.btnTopLeft}"></button>
      </div>
      <div>
        <div class="logo">
          <img src="dialog-images/logo/logo_right.png" alt="logo">
        </div>
      </div>
<!--      <div>-->
<!--        <div v-show="getHeaderBtnLeftPhoto === true" class="logoNewStart">-->
<!--          <img src="dialog-images/logo/logo_right.png" alt="logoNewStart">-->
<!--        </div>-->
<!--      </div>-->
    </div>
  </div>
</template>

<script>
import { mapGetters, mapActions } from 'vuex'
import { PromobotLogger, EventInitiatorTypes, EventTypes } from 'promobot-logger'

export default {
  name: 'header-component',
  data () {
    return {
      clearCounter: 0
    }
  },
  computed: {
    ...mapGetters('app', [
      'getStep',
      'getStatesNoBack',
      'getLoadAppSettings'
    ]),
    ...mapGetters('ui', [
      'getHeaderEnabled',
      'getHeaderEnabledPodHeader',
      'getHeaderBtnLeftText',
      'getHeaderBtnLeftAction',
      'getHeaderBtnLeftEnabled',
      'getHeaderBtnLeftPhoto'
    ]),
    ...mapGetters('engine', [
      'getCurrentStateName'
    ]),
    ...mapGetters('robot', [
      'getFaceRecognizeGeneralFrame',
      'getUserGet'
    ]),
    topLineStyle () {
      return this.getLoadAppSettings ? { ...this.getLoadAppSettings.topLine } : { background: '#95C11F' }
    }
  },
  methods: {
    ...mapActions('engine', [
      'handlerClickMoveToState'
    ]),
    ...mapActions('robot', [
      'clickAnswer'
    ]),
    ...mapActions('robot', [
      'abortRobotReplic'
    ]),
    resetLocalStorage: function (event) {
      if (event.clientX > 1230 && event.clientY < 80) {
        this.clearCounter++
      } else if (this.clearCounter > 0) {
        this.clearCounter = 0
      }
      if (this.clearCounter > 5) {
        this.clearCounter = 0
        let passw = prompt('Введите пароль для очистки LocalStorage')
        if (passw === '123456') {
          localStorage.clear()
          alert('LocalStorage очищен. Кейс будет перезапущен')
          window.location.reload(true)
        } else {
          alert('Пароль неверный')
        }
      }
    },
    bntAction: function () {
      let logger = PromobotLogger.getInstance()
      let eventId = logger.logEvent(EventInitiatorTypes.USER, EventTypes.CLICK)
      for (let key in this.$store.getters['ui/getHeaderBtnLeftAction']) {
        this.$store.dispatch(key, {
          meta: { eventId },
          data: this.getHeaderBtnLeftAction[key]
        })
      }
    }
  }
}
</script>

