<template>
  <div class="container-meeting" v-if="showComponent">
    <div class="content_block">
      <h2></h2>
      <div class="content-photo">
        <img :src="getFaceRecognizeGeneralFrame" alt="" title="" />
      </div>
      <div class="name_input" :style="meetingInputStyle">
        <button :class="['btn_talk', getMeetingTalk === true ? 'btn_talk_stop' : 'btn_talk_start']" @click="setTalk" />
        <div class="clear" @click="clearInput()"><div></div><div></div></div>
        <input id="meeting_input" v-model.trim="name" placeholder="Введите ваше имя" autocomplete="off" />
        <button v-if="getLoadAppSettings" id="meetBtn" class="go_btn" :disabled="disabledBtn" v-html="getIconsSVG.next" @click="meet"/>
      </div>
    </div>
    <div class="button_block" style="display: none;" v-if="getLoadAppSettings">
      <button class="btn" @click="notMe" :style="{ ...getLoadAppSettings.btnTopLeft }">
        На фото не я
      </button>
    </div>
  </div>
</template>

<script>
import { mapGetters, mapActions } from 'vuex'
import { PromobotLogger, EventInitiatorTypes, EventTypes } from 'promobot-logger'

export default {
  name: 'meeting',
  data () {
    return {
      userAwaitTimer: null
    }
  },
  computed: {
    ...mapGetters('app', [
      'getStep',
      'getSessionName',
      'getMeetingTalk',
      'getLoadAppSettings',
      'getIconsSVG'
    ]),
    ...mapGetters('faces', [
      'getUserLost',
      'getUserGeneral'
    ]),
    ...mapGetters('ui', [
      'getSubtitlesEnabled',
      'getUserMet',
      'getSpinnerEnabled'
    ]),
    ...mapGetters('robot', [
      'getFaceRecognizeGeneralFrame'
    ]),
    disabledBtn () {
      return !this.name
    },
    meetingInputStyle () {
      return this.getLoadAppSettings ? { ...this.getLoadAppSettings.inputMeeting } : {}
    },
    name: {
      get () {
        return this.$store.getters['app/getSessionName']
      },
      set (value) {
        let logger = PromobotLogger.getInstance()
        let eventId = logger.logEvent(EventInitiatorTypes.USER, EventTypes.KEYUP)
        this.$store.dispatch('app/setSessionName', {
          meta: { eventId },
          data: value.substring(0, 1).toUpperCase() + value.substring(1).toLowerCase()
        })
        this.$store.dispatch('ui/setUserName', {
          meta: { eventId },
          data: value.substring(0, 1).toUpperCase() + value.substring(1).toLowerCase()
        })
      }
    },
    showComponent () {
      if (this.$store.getters['app/getStep'] === 'meeting') {
        // eslint-disable-next-line vue/no-async-in-computed-properties
        setTimeout(() => {
          if (document.getElementById('meeting_input') && this.$store.getters['ui/getSpinnerEnabled'] === false) {
            document.getElementById('meeting_input').focus()
          }
        }, 100)
      }
      return this.getStep === 'meeting'
    }
  },
  methods: {
    ...mapActions('engine', [
      'handlerClickMoveToState'
    ]),
    ...mapActions('handlers', [
      'faceRecognizeAddFaceRequest'
    ]),
    ...mapActions('robot', [
      'abortRobotReplic'
    ]),
    clearInput: function () {
      let logger = PromobotLogger.getInstance()
      let eventId = logger.logEvent(EventInitiatorTypes.USER, EventTypes.KEYUP)
      this.$store.dispatch('app/setSessionName', {
        meta: { eventId },
        data: ''
      })
      this.$store.dispatch('ui/setUserName', {
        meta: { eventId },
        data: ''
      })
      document.getElementById('meeting_input').focus()
    },
    notMe () {
      let logger = PromobotLogger.getInstance()
      let eventId = logger.logEvent(EventInitiatorTypes.USER, EventTypes.CLICK)
      this.$store.dispatch('engine/handlerMoveToState', {
        meta: { eventId },
        data: 'SELECT_GENERAL'
      })
    },
    setTalk () {
      let logger = PromobotLogger.getInstance()
      let eventId = logger.logEvent(EventInitiatorTypes.USER, EventTypes.CLICK, {
        transition: 'CHANGE-TALK'
      })
      this.abortRobotReplic()
      this.$store.dispatch('app/setMeetingTalk', {
        meta: { eventId },
        data: !this.getMeetingTalk
      })
    },
    meet (e) {
      let logger = PromobotLogger.getInstance()
      let eventId = logger.logEvent(EventInitiatorTypes.USER, EventTypes.KEYUP)
      if (this.$store.getters['ui/getUserMet'] === 3) {
        this.$store.dispatch('ui/setSpinnerEnabled', {
          meta: { eventId },
          data: true
        })
        this.$store.dispatch('robot/sendDialogMuteOn', {
          meta: { eventId }
        })
        this.$store.dispatch('acquaintance/start', {
          meta: { eventId },
          data: true
        })
      } else {
        this.$store.dispatch('robot/userGetRequest', {
          meta: { eventId },
          data: this.getUserGeneral.id
        })
        this.$store.dispatch('engine/handlerMoveToState', {
          meta: { eventId },
          data: 'MAIN_WIN'
        })
      }
    }
  },
  watch: {
    getStep (val) {
      if (val === 'meeting') {
        clearTimeout(this.userAwaitTimer)
        this.userAwaitTimer = setTimeout(() => {
          const eventId = global.logger.logEvent(EventInitiatorTypes.USER, EventTypes.CLICK)
          this.$store.dispatch('engine/handlerMoveToState', {
            meta: { eventId },
            data: 'PROMO'
          })
        }, 20000)
      } else if (this.userAwaitTimer) {
        clearTimeout(this.userAwaitTimer)
      }
    }
  }
}
</script>

