<template>
  <div v-show="showComponent" class="wrapper">
    <div class="container-meeting" v-if="showComponent && stepVisibleData === 'ibs-scales'">
      <div class="content_block">
        <div class="fact">{{ stepData[paramData].title }}</div>
        <div class="img_block">
          <img v-if="getLoadAppSettings.icons.activeSvg === false" :src="stepData[paramData].img" />
          <div v-if="getLoadAppSettings.icons.activeSvg === true" v-html="stepData[paramData].svg"></div>
        </div>
        <div class="liner" :data-width="getDataWidth(getLiner[paramData])">
          <div v-for="(f, index) in getLiner[paramData]" v-bind:key="index" @click="setUserData(f.data)" @mouseenter="setUserData(f.data)" :class="activeData(f.data)" :style="{ ...getLoadAppSettings.scalesStyle }">
            <div class="point"><div :style="{ ...getLoadAppSettings.scalesStyle }"></div></div>
            <div class="liner_text" v-text="f.name"></div>
          </div>
        </div>
      </div>
      <div class="button_block" v-if="getLoadAppSettings">
        <button class="btn" @click="goNext(paramData)" :style="buttonStyle">Я не знаю</button>
        <button class="btn" @click="goNext()" :style="buttonStyle">Продолжить</button>
      </div>
    </div>
    <div class="container-meeting" v-if="showComponent && stepVisibleData === 'ibs-question'">
      <div class="content_block">
        <div class="fact">Были ли проблемы с болезнями сердца в вашей семье у мужчин до 60 и у женщин до 55?</div>
        <img v-if="getLoadAppSettings.icons.activeSvg === false" src="dialog-images/consultation/relativesProblems.png" />
        <div v-if="getLoadAppSettings.icons.activeSvg === true" v-html="familySick"></div>
      </div>
      <div class="button_block" v-if="getLoadAppSettings">
        <button class="btn" @click="relativesProblems(false)" :style="buttonStyle">Нет</button>
        <button class="btn" @click="relativesProblems(true)" :style="buttonStyle">Да</button>
      </div>
    </div>
  </div>
</template>

<script>
import { mapGetters } from 'vuex'
import { PromobotLogger, EventInitiatorTypes, EventTypes } from 'promobot-logger'

export default {
  name: 'ibs',
  components: {

  },
  data () {
    return {
      stepData: {
        0: {
          'title': 'Скажите ваше обычное систолическое (верхнее) артериальное давление',
          'img': 'dialog-images/consultation/pressure.png',
          'svg': false
        },
        1: {
          'title': 'Скажите, какой у Вас уровень холестерина?',
          'img': 'dialog-images/consultation/cholesterol.png',
          'svg': false
        }
      },
      familySick: false,
      liner: {
        0: [
          { 'data': '90', 'name': '90', choosen: false },
          { 'data': '95', 'name': '95', choosen: false },
          { 'data': '100', 'name': '100', choosen: false },
          { 'data': '105', 'name': '105', choosen: false },
          { 'data': '110', 'name': '110', choosen: false },
          { 'data': '115', 'name': '115', choosen: false },
          { 'data': '120', 'name': '120', choosen: false },
          { 'data': '125', 'name': '125', choosen: false },
          { 'data': '130', 'name': '130', choosen: false },
          { 'data': '135', 'name': '135', choosen: false },
          { 'data': '140', 'name': '140', choosen: false },
          { 'data': '145', 'name': '145', choosen: false },
          { 'data': '150', 'name': '150', choosen: false },
          { 'data': '155', 'name': '155', choosen: false },
          { 'data': '160', 'name': '160', choosen: false },
          { 'data': '165', 'name': '165', choosen: false },
          { 'data': '170', 'name': '170', choosen: false },
          { 'data': '175', 'name': '175', choosen: false },
          { 'data': '180', 'name': '180', choosen: false },
          { 'data': '185', 'name': '185', choosen: false },
          { 'data': '190', 'name': '190', choosen: false },
          { 'data': '195', 'name': '195', choosen: false },
          { 'data': '200', 'name': '200', choosen: false }
        ],
        1: [
          { 'data': '3', 'name': 'меньше 4', choosen: false },
          { 'data': '4', 'name': '4', choosen: false },
          { 'data': '5', 'name': '5', choosen: false },
          { 'data': '6', 'name': '6', choosen: false },
          { 'data': '7', 'name': '7', choosen: false },
          { 'data': '8', 'name': '8', choosen: false },
          { 'data': '9', 'name': 'больше 8', choosen: false }
        ]
      },
      info: null,
      muteTimeout: null
    }
  },
  watch: {
    getToldIbs: function (val) {
      if (this.muteTimeout !== null) clearTimeout(this.muteTimeout)
      let th = this
      let logger = PromobotLogger.getInstance()
      let eventId = logger.logEvent(EventInitiatorTypes.USER, EventTypes.CLICK)
      this.liner[this.$store.getters['ui/getIbsStep']].forEach(function (item, i, arr) {
        if ((th.$store.getters['ui/getIbsStep'] === 0 && (Number(val) >= Number(item.data) - 4) && Number(val) <= Number(item.data)) || (th.$store.getters['ui/getIbsStep'] === 1 && val === item.data)) {
          th.setUserData(item.data)
          th.$store.dispatch('robot/sayText', {
            meta: { eventId },
            data: 'Нажмите продолжить'
          })
          th.$store.dispatch('robot/sendDialogMuteOn', {
            meta: { eventId }
          })
          setTimeout(() => {
            th.$store.dispatch('robot/sendDialogMuteOff', {
              meta: { eventId }
            })
          }, 2000)
        }
      })
    }
  },
  computed: {
    ...mapGetters('app', [
      'getStep',
      'getSessionName',
      'getMeetingTalk',
      'getLoadAppSettings',
      'getIconsSVG'
    ]),
    ...mapGetters('ui', [
      'getSubtitlesEnabled',
      'getImtStep',
      'getUserGrowth',
      'getUserSmoke',
      'getUserArtPressure',
      'getUserCholesterol',
      'getIbsStep',
      'getToldIbs',
      'getRelativesProblems'
    ]),
    ...mapGetters('engine', [
      'getCurrentStateName'
    ]),
    buttonStyle () {
      return this.getLoadAppSettings ? { ...this.getLoadAppSettings.btnMain } : {
        background: '#2589DE',
        borderColor: '#2589DE'
      }
    },
    // eslint-disable-next-line vue/return-in-computed-property
    getLiner () {
      if (typeof this.liner[this.$store.getters['ui/getIbsStep']] !== 'undefined') {
        let th = this
        this.liner[this.$store.getters['ui/getIbsStep']].forEach(function (item, i, arr) {
          (item.choosen === th.$store.getters['ui/getUserArtPressure']) ? item.choosen = true : item.choosen = false
        })
        return this.liner
      }
    },
    showComponent () {
      if (this.$store.getters['app/getStep'] === 'ibs') {
        // eslint-disable-next-line vue/no-side-effects-in-computed-properties
        this.stepData[0].svg = this.getIconsSVG.bloodPressure
        // eslint-disable-next-line vue/no-side-effects-in-computed-properties
        this.stepData[1].svg = this.getIconsSVG.cholesterol
        // eslint-disable-next-line vue/no-side-effects-in-computed-properties
        this.familySick = this.getIconsSVG.familySick
      }
      return this.$store.getters['app/getStep'] === 'ibs'
    },
    paramData () {
      if (this.$store.getters['ui/getIbsStep'] === null) {
        let logger = PromobotLogger.getInstance()
        let eventId = logger.logEvent(EventInitiatorTypes.USER, EventTypes.CLICK)
        this.$store.dispatch('ui/setIbsStep', {
          meta: { eventId },
          data: 0
        })
      }
      return this.$store.getters['ui/getIbsStep']
    },
    stepVisibleData () {
      return (this.$store.getters['ui/getIbsStep'] <= 1) ? 'ibs-scales' : 'ibs-question'
    }
  },
  methods: {
    relativesProblems: function (value = false) {
      let logger = PromobotLogger.getInstance()
      let eventId = logger.logEvent(EventInitiatorTypes.USER, EventTypes.CLICK)
      this.$store.dispatch('ui/setRelativesProblems', {
        meta: { eventId },
        data: value
      })
      this.goNext()
    },
    goNext: function (step = null) {
      let logger = PromobotLogger.getInstance()
      let eventId = logger.logEvent(EventInitiatorTypes.USER, EventTypes.CLICK)
      if (step !== null) {
        if (step === 0) {
          this.$store.dispatch('ui/setUserArtPressure', {
            meta: { eventId },
            data: 120
          })
          this.$store.dispatch('ui/setUserArtPressureEnter', {
            meta: { eventId },
            data: null
          })
        } else if (step === 1) {
          this.$store.dispatch('ui/setUserCholesterol', {
            meta: { eventId },
            data: 4
          })
          this.$store.dispatch('ui/setUserCholesterolEnter', {
            meta: { eventId },
            data: null
          })
        }
      }
      if (this.$store.getters['ui/getIbsStep'] === 2) {
        let logger = PromobotLogger.getInstance()
        let eventId = logger.logEvent(EventInitiatorTypes.USER, EventTypes.CLICK)
        this.$store.dispatch('engine/handlerClickMoveToState', {
          meta: { eventId },
          data: 'IBS-RESULT'
        })
      } else {
        this.$store.dispatch('ui/setIbsStep', {
          meta: { eventId },
          data: this.$store.getters['ui/getIbsStep'] + 1
        })
        let action = 'IBS-' + this.$store.getters['ui/getIbsStep']
        if (step !== null && this.$store.getters['ui/getIbsStep'] === 2) action = action + '-1'
        this.$store.dispatch('engine/handlerClickMoveToState', {
          meta: { eventId },
          data: action
        })
      }
    },
    getDataWidth: function (value) {
      return (value.length <= 10) ? 0 : 1
    },
    activeData: function (value) {
      if (this.$store.getters['ui/getIbsStep'] === 0 && value === this.$store.getters['ui/getUserArtPressure']) return 'activeData'
      if (this.$store.getters['ui/getIbsStep'] === 1 && value === this.$store.getters['ui/getUserCholesterol']) return 'activeData'
    },
    setUserData: function (value) {
      let logger = PromobotLogger.getInstance()
      let eventId = logger.logEvent(EventInitiatorTypes.USER, EventTypes.CLICK)
      if (this.$store.getters['ui/getIbsStep'] === 0) {
        this.$store.dispatch('ui/setUserArtPressure', {
          meta: { eventId },
          data: value
        })
        this.$store.dispatch('ui/setUserArtPressureEnter', {
          meta: { eventId },
          data: value
        })

        let lc = JSON.parse(localStorage.getItem('med_' + String(this.$store.getters['faces/getUserGeneral'].id))) || {}
        let forwardActionsLocalStorage = []
        let date = new Date()
        forwardActionsLocalStorage.push({ 'name': 'ui/setUserArtPressure', 'options': this.$store.getters['ui/getUserArtPressure'], 'type': 'manual', 'date': date.getUTCFullYear() + '/' + (date.getUTCMonth() + 1) + '/' + date.getUTCDate() + '_' + date.getHours() + ':' + date.getMinutes() + ':' + date.getSeconds() })
        lc[5] = forwardActionsLocalStorage
        localStorage.setItem('med_' + String(this.$store.getters['faces/getUserGeneral'].id), JSON.stringify(lc))
      } else if (this.$store.getters['ui/getIbsStep'] === 1) {
        this.$store.dispatch('ui/setUserCholesterol', {
          meta: { eventId },
          data: value
        })
        this.$store.dispatch('ui/setUserCholesterolEnter', {
          meta: { eventId },
          data: value
        })
      }
    }
  }
}
</script>

