<template>
  <div class="container-promo" v-show="showComponent">
    <div class="content_block">
      <div class="start_top">
        <div><img src="../../assets/img/logo.png" /></div>
        <div><img src="../../assets/img/messages.png" /></div>
      </div>
      <div v-if="showComponent">
        <p class="fact" :data-long="computedFact.length > 250" v-text="computedFact"></p>
      </div>
    </div>
    <div class="button_block">
      <button class="btn" :style="btnStyle" @click="startGo" :disabled="getUserMet === 'undefined'">Пройти консультацию</button>
    </div>
  </div>
</template>

<script>
import { mapGetters, mapActions } from 'vuex'
import { PromobotLogger, EventInitiatorTypes, EventTypes } from 'promobot-logger'

export default {
  name: 'start',
  components: {
  },
  computed: {
    ...mapGetters('app', [
      'getStep',
      'getLoadAppSettings'
    ]),
    ...mapGetters('ui', [
      'getSubtitlesEnabled',
      'getFacts',
      'getUserMet'
    ]),
    ...mapGetters('faces', [
      'getUserGeneral'
    ]),
    ...mapGetters('engine', [
      'getCurrentStateName'
    ]),
    ...mapGetters('robot', [
      'getFaceRecognizeInfo'
    ]),
    // eslint-disable-next-line vue/return-in-computed-property
    computedFact () {
      if (this.getStep === 'start') {
        return this.$store.getters['ui/getFacts'][this.getRandomInt(0, this.$store.getters['ui/getFacts'].length - 1)]
      }
    },
    showComponent () {
      let logger = PromobotLogger.getInstance()
      let eventId = logger.logEvent(EventInitiatorTypes.USER, EventTypes.CLICK)
      if (this.$store.getters['faces/getUserGeneral'] !== null && this.$store.getters['app/getStep'] === 'start') {
        this.$store.dispatch('ui/setUserAge', {
          meta: { eventId },
          data: this.$store.getters['faces/getUserGeneral'].age
        })
        this.$store.dispatch('ui/setUserGender', {
          meta: { eventId },
          data: (this.$store.getters['faces/getUserGeneral'].gender === 1) ? 0 : 1
        })
      }
      return this.getStep === 'start'
    },
    btnStyle () {
      return { background: this.getLoadAppSettings?.btn?.color || '#3B5998', borderColor: this.getLoadAppSettings?.btn?.color || '#3B5998' }
    }
  },
  methods: {
    ...mapActions('engine', [
      'handlerClickMoveToState'
    ]),
    getRandomInt (min, max) {
      return Math.floor(Math.random() * (max - min + 1)) + min
    },
    startGo () {
      let logger = PromobotLogger.getInstance()
      let eventId = logger.logEvent(EventInitiatorTypes.USER, EventTypes.CLICK)
      let action = 'SELECT_GENERAL'
      this.$store.dispatch('engine/handlerClickMoveToState', {
        meta: { eventId },
        data: action
      })
    }
  }
}
</script>

