        <div :key="index" v-for="(tile, index) in getLoadAppSettings.tiles.filter(item => item.active === 1)">
          <div v-if="tile.type === EXAMINATION_TYPE.CONSULTATION" @click="doExamination(EXAMINATION_TYPE.CONSULTATION)" id="go_1" :style="{...tile.style}">
            <table>
              <tr>
                <td><img src="../../assets/img/start_new1.png"></td>
                <td></td>
              </tr>
              <tr>
                <td><p v-html="tile.name"></p></td>
                <td></td>
              </tr>
            </table>
          </div>
          <div v-if="tile.type === EXAMINATION_TYPE.GLUCOMETER" :style="(typeof resData[2] !== 'undefined' && resData[2].color !== null) ? {background:resData[2].color} : { ...tile.style }" @click="doExamination(EXAMINATION_TYPE.GLUCOMETER)">
            <table :data-isData="getUserGlucometry !== null">
              <tr>
                <td><img src="../../assets/img/start_new2.png"></td>
                <td>
                  <h3>{{ fRound(getUserGlucometry, 1) }}</h3>
                  <p class="note">ммоль/л</p>
                </td>
              </tr>
              <tr>
                <td><p v-html="tile.name"></p></td>
                <td><p v-text="(typeof resData[2] !== 'undefined') ? resData[2].text : false"></p></td>
              </tr>
            </table>
          </div>
          <div v-if="tile.type === EXAMINATION_TYPE.WEIGHT_HEIGHT" :style="(typeof resData[3] !== 'undefined' && resData[3].color !== null) ? {background:resData[3].color} : { ...tile.style }" @click="doExamination(tile.type)">
            <table :data-isData="getUserWeight !== null && getUserGrowth !== null">
              <tr>
                <td><img src="../../assets/img/start_new3.png"></td>
                <td>
                  <div class="divider_block">
                    <div>
                      <h3>{{ fRound(getUserGrowth, 0) }}</h3>
                      <p class="note">см</p>
                    </div>
                    <div class="divider">
                      <h3>/</h3>
                    </div>
                    <div>
                      <h3>{{ fRound(getUserWeight, 1) }}</h3>
                      <p class="note">кг</p>
                    </div>
                  </div>
                </td>
              </tr>
              <tr>
                <td><p v-html="tile.name"></p></td>
                <td><p v-text="(typeof resData[3] !== 'undefined') ? resData[3].text : false"></p></td>
              </tr>
            </table>
          </div>
          <div v-if="tile.type === EXAMINATION_TYPE.PULSEOXIMETER_SPIROMETER" :style="(typeof resData[4] !== 'undefined' && resData[4].color !== null) ? {background:resData[4].color} : { ...tile.style }" @click="doExamination(tile.type)">
            <table :data-isData="getUserSpirographia !== null">
              <tr>
                <td>
                  <img v-if="tile.active_spir && !tile.active_sat" src="../../assets/img/start_new4_lungs.png">
                  <img v-else src="../../assets/img/start_new4.png">
                </td>
                <td>
                  <template v-if="getUserSaturatsiya">
                    <h3>{{ fRound(getUserSaturatsiya, 0) }}</h3>
                    <p class="note">%</p>
                  </template>
                </td>
              </tr>
              <tr>
                <td><p v-html="tile.name"></p></td>
                <td><p v-html="(typeof resData[4] !== 'undefined') ? resData[4].text : ''"></p></td>
              </tr>
            </table>
          </div>
          <div v-if="tile.type === EXAMINATION_TYPE.TONOMETER" :style="(typeof resData[5] !== 'undefined' && resData[5].color !== null) ? {background:resData[5].color} : { ...tile.style }" @click="doExamination(tile.type)">
            <table :data-isData="getUserArtPressure !== null && getUserArtPressureLow !== null && getUserPulse !== null">
              <tr>
                <td><img src="../../assets/img/start_new5.png"></td>
                <td>
                  <div class="divider_block">
                    <div>
                      <h3>{{ fRound(getUserArtPressure, 0) }}<span v-if="getUserArtPressureLow">/{{ fRound(getUserArtPressureLow, 0) }}</span></h3>
                      <p class="note">давление</p>
                    </div>
                    <div v-if="getUserPulse">
                      <h3>{{ fRound(getUserPulse, 0) }}</h3>
                      <p class="note">пульс</p>
                    </div>
                  </div>
                </td>
              </tr>
              <tr>
                <td><p v-html="tile.name"></p></td>
                <td><p v-text="(typeof resData[5] !== 'undefined') ? resData[5].text : false"></p></td>
              </tr>
            </table>
          </div>
          <div v-if="tile.type === EXAMINATION_TYPE.THERMO" :style="(typeof resData[6] !== 'undefined' && resData[6].color !== null) ? {background:resData[6].color} : { ...tile.style }" @click="doExamination(tile.subtype)">
            <table :data-isData="getUserTemperature !== null">
              <tr>
                <td><img src="../../assets/img/start_new6.png"></td>
                <td>
                  <h3>{{ fRound(getUserTemperature, 1) }}</h3>
                  <p class="note">&deg;C</p>
                </td>
              </tr>
              <tr>
                <td><p v-html="tile.name"></p></td>
                <td><p v-text="(typeof resData[6] !== 'undefined') ? resData[6].text : false"></p></td>
              </tr>
            </table>
          </div>
        </div>

      </div>
    </div>
    <div class="button_block">

    </div>
  </div>
</template>

<script>
/* eslint-disable vue/no-side-effects-in-computed-properties */
import { mapGetters, mapActions } from 'vuex'
import { PromobotLogger, EventInitiatorTypes, EventTypes } from 'promobot-logger'
import { getSpirigraphiaData, getSpirigraphiaDataCompare } from '@/utils'
import { EXAMINATION_TYPE, TOPIC_DATA } from '@/constants'
// import settings from '@/settings'
const uuidv4 = require('uuid/v4')

export default {
  name: 'startNew',
  data () {
    return {
      resData: {},
      step: null,
      EXAMINATION_TYPE,
      TOPIC_DATA
    }
  },
  computed: {
    ...mapGetters('app', [
      'getStep',
      'getLoadAppSettings'
    ]),
    ...mapGetters('ui', [
      'getSubtitlesEnabled',
      'getFacts',
      'getUserMet',
      'getUserName',
      'getUserWeight',
      'getUserGrowth',
      'getUserArtPressure',
      'getUserCholesterol',
      'getUserSmoke',
      'getUserAge',
      'getUserGender',
      'getRelativesProblems',
      'getHeaderEnabled',
      'getHeaderEnabledPodHeader',
      'getFooterEnabled',
      'getImtStep',
      'getIbsStep',
      'getUserMet',
      'getImtMistake',
      'getUserGlucometry',
      'getUserSpirographia',
      'getUserSaturatsiya',
      'getUserPulse',
      'getUserArtPressureLow',
      'getUserTemperature',
      'getUserSpirographiaQ1',
      'getUserSpirographiaQ2',
      'getIsExaminationStarted'
    ]),
    ...mapGetters('faces', [
      'getUserGeneral'
    ]),
    ...mapGetters('engine', [
      'getCurrentStateName'
    ]),
    ...mapGetters('robot', [
      'getFaceRecognizeInfo',
      'getUserGet'
    ]),
    getUserSpirographiaTiffno () {
      return this.getUserSpirographia && ((Number(this.getUserSpirographia['FEV1']) / Number(this.getUserSpirographia['FVC'])) * 100).toFixed(0)
    },
    showComponent () {
      if (this.getStep === 'start_new') {
        // console.warn('При переходе на главный экран главного: ', JSON.stringify(this.$store.getters['faces/getUserGeneral']) )
        let logger = PromobotLogger.getInstance()
        let eventId = logger.logEvent(EventInitiatorTypes.USER, EventTypes.CLICK)
        if (this.step === null) {
          this.step = (this.getIsExaminationStarted === null) ? 'START_NEW' : 'START_NEW1'
          this.$store.dispatch('robot/sayReplicByName', {
            meta: { eventId },
            data: { 'step': this.step, 'terminate': true }
          })
        }

        if (this.$store.getters['faces/getUserGeneral'] !== null && this.$store.getters['app/getStep'] === 'start_new') {
          this.$store.dispatch('ui/setUserAge', {
            meta: { eventId },
            data: this.$store.getters['faces/getUserGeneral'].age
          })
          this.$store.dispatch('ui/setUserGender', {
            meta: { eventId },
            data: (this.$store.getters['faces/getUserGeneral'].gender === 1) ? 0 : 1
          })
        }
        this.resData = {}
        this.calculateResults()
      } else {
        if (this.step !== null) this.step = null
      }
      return this.getStep === 'start_new'
    }
  },
  methods: {
    ...mapActions('engine', [
      'handlerClickMoveToState'
    ]),
    ...mapActions('handlers', [
      'userClickHandler'
    ]),
    resultSpirographiaColor: function (present, type) {
      return getSpirigraphiaDataCompare(present, type)
    },
    getSpirigraphiaDataSource: function (h, a, p, type) {
      if (this.getUserSpirographia !== null) return ((this.getUserSpirographia[type] / getSpirigraphiaData(h, a, p, type)) * 100).toFixed(0)
      return ''
    },
    fRound: function (data, num) {
      return (data === null) ? '' : String(Number(data).toFixed(num)).replace('.', ',')
    },
    doExamination: function (examination) {
      let logger = PromobotLogger.getInstance()
      let eventId = logger.logEvent(EventInitiatorTypes.USER, EventTypes.CLICK)
      let actions = []
      if (examination === EXAMINATION_TYPE.THERMO_HEAD) {
        // localStorage.setItem('tempSettings', JSON.stringify({
        //   userId: this.$store.getters['faces/getUserGeneral'].id,
        //   case: true,
        //   url: 'some case url'
        // }))
        // location.href = settings.thermocontrol.url
        const options = {
          replica: {
            id: {
              uuid: uuidv4()
            },
            actions: 'app:org.promobot.termo',
            text: '"',
            type: 21
          },
          terminate: true
        }
        const thermoRequest = { userId: this.getUserGeneral.id }
        localStorage.setItem('tempSettings', JSON.stringify(thermoRequest))
        // actions.push({ 'name': 'ui/setMeasurementStep', 'options': 1, 'timeout': 0 })
        // actions.push({ 'name': 'ui/setMeasurementNum', 'options': examination, 'timeout': 0 })
        actions.push({ 'name': 'robot/dialogSayReplicByDataRequest', 'options': options, 'timeout': 0 })
      } else if (examination === EXAMINATION_TYPE.CONSULTATION) {
        actions.push({ 'name': 'ui/setIsExaminationStarted', 'options': true, 'timeout': 0 })
        actions.push({ 'name': 'ui/setSpinnerEnabled', 'options': true, 'timeout': 0 })
        actions.push({ 'name': 'ui/setMeasurementStep', 'options': 1, 'timeout': 0 })
        actions.push({ 'name': 'ui/setMeasurementNum', 'options': EXAMINATION_TYPE.WEIGHT_HEIGHT, 'timeout': 0 })
      } else {
        let step = 1
        // Если пульсоксиметр отключен а спирограф активен - переходить сразу к спирографии
        if (examination === EXAMINATION_TYPE.PULSEOXIMETER_SPIROMETER && this.getLoadAppSettings.tiles.filter(item => item.type === 4)[0].active_sat === 0 && this.getLoadAppSettings.tiles.filter(item => item.type === 4)[0].active_spir === 1) step = 4
        actions.push({ 'name': 'ui/setIsExaminationStarted', 'options': false, 'timeout': 0 })
        actions.push({ 'name': 'ui/setSpinnerEnabled', 'options': true, 'timeout': 0 })
        actions.push({ 'name': 'ui/setMeasurementStep', 'options': step, 'timeout': 0 })
        actions.push({ 'name': 'ui/setMeasurementNum', 'options': examination, 'timeout': 0 })
      }
      actions.forEach(item => {
        setTimeout(() => {
          this.$store.dispatch(item.name, { meta: { eventId }, data: item.options })
        }, item.timeout)
      })
    },
    calculateResults () {
      // ключи массива строки, так как нумирация с 2
      // создаем объект с результатами измерений по приборам и заполняем пустыми стилями плиток
      Object.values(this.EXAMINATION_TYPE).forEach(examinationType => {
        if (examinationType !== this.EXAMINATION_TYPE.CONSULTATION) this.resData[examinationType] = { color: null, text: '' }
      })
      for (let examinationType in this.resData) {
        if (examinationType === this.EXAMINATION_TYPE.PULSEOXIMETER_SPIROMETER.toString()) {
          if (this.getUserSaturatsiya !== null) {
            if (this.getUserSaturatsiya >= 95) {
              this.resData[examinationType].color = '#9DC900'
              this.resData[examinationType].text = 'Норма'
            } else if (this.getUserSaturatsiya >= 90) {
              this.resData[examinationType].color = '#FEB041'
              this.resData[examinationType].text = 'Ниже нормы'
            }
          }
          if (this.getUserSpirographia !== null
                  && this.getUserAge !== null
                  && this.getUserGender !== null
                  && this.getUserSpirographia !== null
                  && this.getUserSpirographiaQ1 !== null
                  && this.getUserSpirographiaQ2 !== null
          ) {
            let s = {}
            s['FVC'] = this.resultSpirographiaColor(this.getSpirigraphiaDataSource(this.getUserGrowth, this.getUserAge.toFixed(0), this.getUserGender, 'FVC'), 'FVC')
            s['FEV1'] = this.resultSpirographiaColor(this.getSpirigraphiaDataSource(this.getUserGrowth, this.getUserAge.toFixed(0), this.getUserGender, 'FEV1'), 'FEV1')
            s['PEF'] = this.resultSpirographiaColor(this.getSpirigraphiaDataSource(this.getUserGrowth, this.getUserAge.toFixed(0), this.getUserGender, 'PEF'), 'PEF')
            s['FEV1/FVC'] = this.resultSpirographiaColor(this.getUserSpirographiaTiffno, 'FEV1/FVC')
            let m = Math.max(s['FVC'], s['FEV1'], s['FEV1/FVC'], s['PEF'])
            // let m = s['FEV1/FVC']
            // console.log('m', m)
            if (m === 1) {
              this.resData[examinationType].color = '#FEB041'
              this.resData[examinationType].text = 'Спирометрия:</br>Ниже нормы'
            } else if (m === 2) {
              this.resData[examinationType].color = '#FD572F'
              this.resData[examinationType].text = 'Спирометрия:</br>Ниже нормы'
            } else if (m === 3) {
              this.resData[examinationType].color = '#B82F14'
              this.resData[examinationType].text = 'Спирометрия:</br>Значительно ниже нормы'
            } else {
              this.resData[examinationType].color = '#9DC900'
              this.resData[examinationType].text = 'Спирометрия:</br>Норма'
            }
          }
        }
        if (examinationType === this.EXAMINATION_TYPE.TONOMETER.toString() && this.getUserArtPressure !== null && this.getUserPulse !== null) {
          if (this.getUserArtPressure <= 70) {
            this.resData[examinationType].color = '#82CBC2'
            this.resData[examinationType].text = 'Значительно ниже нормы'
          } else if (this.getUserArtPressure <= 90) {
            this.resData[examinationType].color = '#FEB041'
            this.resData[examinationType].text = 'Ниже нормы'
          } else if (this.getUserArtPressure <= 140) {
            this.resData[examinationType].color = '#9DC900'
            this.resData[examinationType].text = 'Норма'
          } else if (this.getUserArtPressure <= 180) {
            this.resData[examinationType].color = '#FD572F'
            this.resData[examinationType].text = 'Выше нормы'
          } else {
            this.resData[examinationType].color = '#B82F14'
            this.resData[examinationType].text = 'Значительно выше нормы'
          }
        }
        if (examinationType === this.EXAMINATION_TYPE.THERMO.toString() && this.getUserTemperature !== null) {
          // if (this.getUserTemperature <= 36) {
          //   this.resData[examinationType].color = '#82CBC2'
          //   this.resData[examinationType].text = 'Пониженная'
          if (this.getUserTemperature <= 37.1) {
            this.resData[examinationType].color = '#9DC900'
            this.resData[examinationType].text = 'Норма'
          } else {
            this.resData[examinationType].color = '#FEB041'
            this.resData[examinationType].text = 'Повышенная'
          }// else {
          //   this.resData[examinationType].color = '#B82F14'
          //   this.resData[examinationType].text = 'Гораздо выше нормы'
          // }
        } else if (examinationType === this.EXAMINATION_TYPE.GLUCOMETER.toString() && this.getUserGlucometry !== null) {
          if (this.getUserGlucometry <= 3.3) {
            this.resData[examinationType].color = '#82CBC2'
            this.resData[examinationType].text = 'Пониженный'
          } else if (this.getUserGlucometry <= 5.5) {
            this.resData[examinationType].color = '#9DC900'
            this.resData[examinationType].text = 'Норма'
          } else if (this.getUserGlucometry <= 10) {
            this.resData[examinationType].color = '#FEB041'
            this.resData[examinationType].text = 'Повышенный'
          } else {
            this.resData[examinationType].color = '#B82F14'
            this.resData[examinationType].text = 'Гораздо выше нормы'
          }
        } else if (examinationType === this.EXAMINATION_TYPE.WEIGHT_HEIGHT.toString() && this.getUserWeight !== null && this.getUserGrowth !== null) {
          let imt = this.getUserWeight / Math.pow(this.getUserGrowth / 100, 2)
          if (imt > 30) {
            this.resData[examinationType].color = '#B82F14'
            this.resData[examinationType].text = 'Значительно выше нормы'
          } else if (imt > 25) {
            this.resData[examinationType].color = '#FEB041'
            this.resData[examinationType].text = 'Выше нормы'
          } else if (imt > 20) {
            this.resData[examinationType].color = '#9DC900'
            this.resData[examinationType].text = 'Норма'
          } else {
            this.resData[examinationType].color = '#82CBC2'
            this.resData[examinationType].text = 'Ниже нормы'
          }
        }
      }
    }
  }
}
</script>

