<template>
  <div class="promo__container" v-show="showComponent" @click="promoClick()">
    <img class="promo__img" src="dialog-images/logo/logo_main.png"/>
<!--    <div class="promo__text">Для начала нажмите на экран</div>-->
    <div class="promo__icon" v-html="getIconsSVG && getIconsSVG.fingerPress"></div>
  </div>
</template>

<script>
import { mapGetters, mapActions } from 'vuex'
import { EventInitiatorTypes, EventTypes } from 'promobot-logger'

export default {
  name: 'promo',
  components: {
  },
  computed: {
    ...mapGetters('app', [
      'getStep',
      'getIconsSVG'
    ]),
    ...mapGetters('ui', [
      'getSubtitlesEnabled'
    ]),
    ...mapGetters('engine', [
      'getCurrentStateName'
    ]),
    ...mapGetters('robot', [
      'getFaceRecognizeInfo'
    ]),
    showComponent () {
      return this.getStep === 'promo'
    }
  },
  methods: {
    ...mapActions('engine', [
      'handlerClickMoveToState'
    ]),
    goToState (state) {
      this.handlerClickMoveToState({
        transition: state,
        data: state
      })
    },
    promoClick: function () {
      if (['PROMO'].includes(this.$store.getters['engine/getCurrentStateName'])) {
        let eventId = global.logger.logEvent(EventInitiatorTypes.USER, EventTypes.CLICK)
        this.$store.dispatch('engine/handlerClickMoveToState', {
          meta: { eventId },
          data: 'SELECT_GENERAL'
        })
      }
    }
  }
}
</script>

