<template>
    <div class="wrapper" v-show="showComponent">
        <div class="content">
            <div class="div-button">
                <button @click="doBtnStart()">
                  <img class="icon_img" src="../../assets/img/start_new4.png"/>
                  <p>Измерить показатели <br> здоровья</p></button>
                <button @click="doBtnSpecialist()">
                  <img class="icon_img" src="../../assets/img/start_new1.png"/>
                  <p>Пройти опрос <br> специалста</p></button>
            </div>
        </div>
    </div>
</template>

<script>
import { mapGetters, mapActions } from 'vuex'
import { PromobotLogger, EventInitiatorTypes, EventTypes } from 'promobot-logger'

export default {
  name: 'main_win',
  computed: {
    ...mapGetters('app', [
      'getStep'
    ]),
    ...mapGetters('engine', [
      'getCurrentStateName'
    ]),
    showComponent () {
      return this.getStep === 'main_win'
    }
  },
  methods: {
    ...mapActions('engine', [
      'handlerClickMoveToState'
    ]),
    goToState (state) {
      this.handlerClickMoveToState({
        transition: state,
        data: state
      })
    },
    doBtnStart: function () {
      let logger = PromobotLogger.getInstance()
      let eventId = logger.logEvent(EventInitiatorTypes.USER, EventTypes.CLICK)
      this.$store.dispatch('engine/handlerClickMoveToState', {
        meta: { eventId },
        data: 'START_NEW'
      })
    },
    doBtnSpecialist: function () {
      let logger = PromobotLogger.getInstance()
      let eventId = logger.logEvent(EventInitiatorTypes.USER, EventTypes.CLICK)
      this.$store.dispatch('engine/handlerClickMoveToState', {
        meta: { eventId },
        data: 'SPECIALIST_NEW'
      })
    }
  }
}
</script>
