<template>
    <div v-show="showComponent" class="wrapper">
      <div class="content-main content">
        <p>{{this.getQuest}}</p>
            <div class="img-box">
                <img class="img-quest" :src="itemImageQuestion">
            </div>
            <div class="yes-no">
                <button v-on:click="next(1)">Да</button>
                <button v-on:click="next(0)">Нет</button>
            </div>
      </div>
    </div>
  </template>
<script>
import { mapGetters, mapActions } from 'vuex'
import { getLenght } from '../../store/modules/application/specialist'
import { getName, getFunc } from '../../store/question'
import { PromobotLogger, EventInitiatorTypes, EventTypes } from 'promobot-logger'

export default {
  name: 'quest_new_new',
  data () {
    return {
      length_quest: 0,
      question: '',
      path_img: '',
      indexStep: null,
      stringQuest: '',
      yes: ''
    }
  },
  updated () {
    this.length_quest = getLenght(this.getSpecialistNum)
    this.indexStep = this.getStepQuest
    this.question = this.getQuest
    this.path_img = this.getPath
  },
  computed: {
    ...mapGetters('app', [
      'getStep'
    ]),
    ...mapGetters('ui', [
      'getSpecialistNum',
      'getStepQuest',
      'getQuest',
      'getPath',
      'getYes'
    ]),
    ...mapGetters('engine', [
      'getCurrentStateName'
    ]),
    showComponent () {
      return this.getStep === 'quest_new_new'
    },
    itemImageQuestion () {
      return require(`../../assets/specialist/${this.path_img}/${this.indexStep}.png`)
    }
  },
  methods: {
    ...mapActions('ui', [
      'setSpecialistNum',
      'setStepQuest',
      'setQuest',
      'setPath',
      'setYes'
    ]),
    ...mapActions('engine', [
      'handlerClickMoveToState'
    ]),
    goToState (state) {
      this.handlerClickMoveToState({
        transition: state,
        data: state
      })
    },
    next: function (flag) {
      if (this.indexStep !== (this.length_quest - 1)) {
        let ind = this.indexStep + 1
        let logger = PromobotLogger.getInstance()
        let eventId = logger.logEvent(EventInitiatorTypes.USER, EventTypes.CLICK)
        this.$store.dispatch('ui/setStepQuest', {
          meta: { eventId },
          data: ind
        })
        let str = getName(this.getSpecialistNum)
        console.log(str)
        console.log('INDD = ' + ind)
        let q = getFunc(str, ind)
        console.log('q === ' + q)
        this.$store.dispatch('ui/setQuest', {
          meta: { eventId },
          data: q
        })
        if (flag === 1) {
          this.$store.dispatch('ui/setYes', {
            meta: { eventId },
            data: 'yes'
          })
        }
      } else {
        console.log('RESULT')
        if (this.getYes === 'yes') {
          let logger = PromobotLogger.getInstance()
          let eventId = logger.logEvent(EventInitiatorTypes.USER, EventTypes.CLICK)
          this.$store.dispatch('engine/handlerClickMoveToState', {
            meta: { eventId },
            data: 'BAD_RESULT'
          })
        } else {
          console.log('good_result  good_result')
          let logger = PromobotLogger.getInstance()
          let eventId = logger.logEvent(EventInitiatorTypes.USER, EventTypes.CLICK)
          this.$store.dispatch('engine/handlerClickMoveToState', {
            meta: { eventId },
            data: 'GOOD_RESULT'
          })
        }
        /*
        let logger = PromobotLogger.getInstance()
        let eventId = logger.logEvent(EventInitiatorTypes.USER, EventTypes.CLICK)
        this.$store.dispatch('ui/setStepQuest', {
          meta: { eventId },
          data: ind
        })
        */
      }
    }
  }
}
