<template>
    <div class="wrapper" v-show="showComponent">
        <div class="content">
            <p>Вы уверены, что хотите выйти?</p>
            <div>
                <button @click="doBtnSpecialist()">К спеиалистам</button>
                <button @click="doBtnMain()">На главную</button>
            </div>
        </div>
    </div>
</template>

<script>
import { mapGetters, mapActions } from 'vuex'
import { PromobotLogger, EventInitiatorTypes, EventTypes } from 'promobot-logger'

export default {
  name: 'exit_view_my',
  computed: {
    ...mapGetters('app', [
      'getStep'
    ]),
    ...mapGetters('engine', [
      'getCurrentStateName'
    ]),
    showComponent () {
      return this.getStep === 'exit_view_my'
    }
  },
  methods: {
    ...mapActions('engine', [
      'handlerClickMoveToState'
    ]),
    goToState (state) {
      this.handlerClickMoveToState({
        transition: state,
        data: state
      })
    },
    doBtnSpecialist: function () {
      let logger = PromobotLogger.getInstance()
      let eventId = logger.logEvent(EventInitiatorTypes.USER, EventTypes.CLICK)
      this.$store.dispatch('engine/handlerClickMoveToState', {
        meta: { eventId },
        data: 'SPECIALIST_NEW'
      })
    },
    doBtnMain: function () {
      let logger = PromobotLogger.getInstance()
      let eventId = logger.logEvent(EventInitiatorTypes.USER, EventTypes.CLICK)
      this.$store.dispatch('engine/handlerClickMoveToState', {
        meta: { eventId },
        data: 'MAIN_WIN'
      })
    }
  }
}
</script>
<style>
.wrapper {
  width: 100%;
  height: 100%;
  font-family: Circe;
}

.content {
  position: relative;
  width: 100%;
  height: 100%;
