    ...mapGetters('engine', [
      'getCurrentStateName'
    ]),
    showComponent () {
      return this.getStep === 'specialist_new'
    }
  },
  methods: {
    ...mapActions('ui', [
      'setSpecialistNum'
    ]),
    ...mapActions('engine', [
