<template>
    <div v-show="showComponent">
        <p>Enter your age!</p>
        <input/>
        <button v-on:click="next">Next</button>
    </div>
</template>

<script>
import { mapGetters, mapActions } from 'vuex'
export default {
  name: 'age_view',
  computed: {
    ...mapGetters('app', [
      'getStep'
    ]),
    ...mapGetters('engine', [
      'getCurrentStateName'
    ]),
    showComponent () {
      return this.getStep === 'age_view'
    }
  },
  methods: {
    ...mapActions('engine', [
      'handlerClickMoveToState'
    ]),
    goToState (state) {
      this.handlerClickMoveToState({
        transition: state,
        data: state
      })
    },
    next: function () {
      let logger = PromobotLogger.getInstance()
      let eventId = logger.logEvent(EventInitiatorTypes.USER, EventTypes.CLICK)
      this.$store.dispatch('engine/handlerClickMoveToState', {
        meta: { eventId },
        data: 'MAIN_WIN'
      })
    }
  }
}
</script>
