<template>
  <div v-if="showComponent" class="wrapper">
    <div class="container-meeting" v-if="showComponent">
      <div class="content_block">
        <div class="ibsDiv">
          <div>
            <div class="tuneBlock">
              <input type="num" disabled :style="tuneInputStyle" v-model="resultTableData.pressure"><br />
              <button class="arrow" @click="changeIbs(0, 1)" :style="tuneBtnStyle"><img src="../../assets/img/arrow-down.png" /></button>
              <button class="arrow" @click="changeIbs(0, -1)" :style="tuneBtnStyle"><img src="../../assets/img/arrow-up.png" /></button>
            </div>
            <h4>Систолическое<br />артериальное<br />давление</h4>
            <p>мм рт. ст</p>
          </div>
          <div>
            <div :key="i" v-for="(c, i) in computedIbsRisk">
              <div :key="m" v-for="(l, m) in c">
                <div :key="j" class="ibsItem" v-for="(d, j) in l" :data-act="d.choosen" @mouseenter="addActive(d.choosen, m, j)">
                  <div v-text="d.data" :data-bgr="d.color"></div>
                </div>
                <br />
              </div>
            </div>
          </div>
          <div>
            <div class="tuneBlock">
              <input type="num" disabled :style="tuneInputStyle" v-model="resultTableData.cholesterol"><br />
              <button class="arrow" @click="changeIbs(1, -1)" :style="tuneBtnStyle"><img src="../../assets/img/arrow-left.png" /></button>
              <button class="arrow" @click="changeIbs(1, 1)" :style="tuneBtnStyle"><img src="../../assets/img/arrow-right.png" /></button>
            </div>
            <h4>Холестерин</h4>
            <p>ммоль/л</p>
          </div>
        </div>
        <h2>{{ nowRisk.title }}</h2>
        <p>{{ nowRisk.text }}</p>
      </div>
      <div class="button_block" v-if="getLoadAppSettings">
        <button
                class="btn"
                @click="bye()"
                :style="buttonStyle">
          Перейти к результатам
        </button>
      </div>
    </div>
  </div>
</template>

<script>
import { mapGetters } from 'vuex'
import { ibsData } from '@/utils'
import { PromobotLogger, EventInitiatorTypes, EventTypes } from 'promobot-logger'

export default {
  name: 'ibsResult',
  components: {

  },
  data () {
    return {
      table: {
        0: [180, 160, 140, 120],
        1: [4, 5, 6, 7, 8]
      },
      resultTableData: {
        age: null,
        gender: null,
        growth: null,
        weight: null,
        smoke: null,
        pressure: null,
        cholesterol: null,
        risk: null
      },
      isTableDataSetup: false,
      ibsRisk: [],
      userData: [],
      nowRisk: { 'risk': null, 'title': null, 'text': null, 'say_text': null },
      last: false
    }
  },
  computed: {
    ...mapGetters('app', [
      'getStep',
      'getSessionName',
      'getMeetingTalk',
      'getLoadAppSettings'
    ]),
    ...mapGetters('ui', [
      'getSubtitlesEnabled',
      'getImtStep',
      'getUserGrowth',
      'getUserWeight',
      'getUserSmoke',
      'getUserArtPressure',
      'getUserCholesterol',
      'getUserAge',
      'getUserGender',
      'getIbsRisk',
      'getUser'
    ]),
    buttonStyle () {
      return this.getLoadAppSettings ? { ...this.getLoadAppSettings.btnMain } : {
        background: '#2589DE',
        borderColor: '#2589DE'
      }
    },
    tuneBtnStyle () {
      return this.getLoadAppSettings ? { ...this.getLoadAppSettings.btnTune } : { backgroundColor: '#CFE09B' }
    },
    tuneInputStyle () {
      return this.getLoadAppSettings ? { ...this.getLoadAppSettings.inputTune } : { borderColor: '#CFE09B' }
    },
    showComponent () {
      if (this.getStep === 'ibsResult') {
        if (this.last === false) {
          // eslint-disable-next-line vue/no-async-in-computed-properties
          setTimeout(() => {
            const logger = PromobotLogger.getInstance()
            const eventId = logger.logEvent(EventInitiatorTypes.USER, EventTypes.CLICK)
            this.$store.dispatch('robot/abortRobotReplic', {
              meta: { eventId }
            })
            this.$store.dispatch('robot/sayText', {
              meta: { eventId },
              data: this.nowRisk.say_text
            })
          }, 50)
        }
        // eslint-disable-next-line vue/no-side-effects-in-computed-properties
        this.last = true
      } else {
        // eslint-disable-next-line vue/no-side-effects-in-computed-properties
        this.last = false
      }
      return this.$store.getters['app/getStep'] === 'ibsResult'
    },
    computedIbsRisk () {
      const _this = this
      let n = 0
      _this.table[0].forEach(function (arterialPressureValue, arterialPressureColumnIndex) {
        if (typeof _this.ibsRisk[n] === 'undefined') {
          _this.ibsRisk[n] = {}
          _this.ibsRisk[n][arterialPressureValue] = {}
        }
        _this.table[1].forEach(function (cholesterolValue, cholesterolRowIndex) {
          if (typeof _this.ibsRisk[n][arterialPressureValue][cholesterolValue] === 'undefined') _this.ibsRisk[n][arterialPressureValue][cholesterolValue] = {}
          _this.ibsRisk[n][arterialPressureValue][cholesterolValue].data = Math.round(ibsData(_this.resultTableData.gender, _this.resultTableData.age, arterialPressureValue, _this.resultTableData.smoke, cholesterolValue))
          if (Number(cholesterolValue) === Number(_this.resultTableData.cholesterol) && (arterialPressureValue - 13) <= _this.resultTableData.pressure && (arterialPressureValue + 7) >= _this.resultTableData.pressure) {
            _this.ibsRisk[n][arterialPressureValue][cholesterolValue].choosen = true
            _this.userData = [arterialPressureColumnIndex, cholesterolRowIndex]
            _this.nowRisk.risk = _this.ibsRisk[n][arterialPressureValue][cholesterolValue].data
            _this.resultTableData.risk.map(function (IbsRiskValue, IbsRiskIndex) {
              if (_this.nowRisk.risk >= IbsRiskValue.start && _this.nowRisk.risk < IbsRiskValue.stop) {
                _this.nowRisk.title = IbsRiskValue.title
                _this.nowRisk.text = IbsRiskValue.write_text
                _this.nowRisk.say_text = IbsRiskValue.say_text
              }
            })
          } else {
            _this.ibsRisk[n][arterialPressureValue][cholesterolValue].choosen = false
          }
          if (_this.ibsRisk[n][arterialPressureValue][cholesterolValue].data >= 15 && _this.ibsRisk[n].length === 0) {
            _this.ibsRisk[n][arterialPressureValue][cholesterolValue].color = 6
          } else if (_this.ibsRisk[n][arterialPressureValue][cholesterolValue].data >= 10) {
            _this.ibsRisk[n][arterialPressureValue][cholesterolValue].color = 5
          } else if (_this.ibsRisk[n][arterialPressureValue][cholesterolValue].data >= 5) {
            _this.ibsRisk[n][arterialPressureValue][cholesterolValue].color = 4
          } else if (_this.ibsRisk[n][arterialPressureValue][cholesterolValue].data >= 3) {
            _this.ibsRisk[n][arterialPressureValue][cholesterolValue].color = 3
          } else if (_this.ibsRisk[n][arterialPressureValue][cholesterolValue].data === 2) {
            _this.ibsRisk[n][arterialPressureValue][cholesterolValue].color = 2
          } else if (_this.ibsRisk[n][arterialPressureValue][cholesterolValue].data === 1) {
            _this.ibsRisk[n][arterialPressureValue][cholesterolValue].color = 1
          } else if (_this.ibsRisk[n][arterialPressureValue][cholesterolValue].data === 0) {
            _this.ibsRisk[n][arterialPressureValue][cholesterolValue].color = 0
          }
        })
        n++
      })
      return _this.ibsRisk
    },
    preparePressure () {
      if (Number(this.getUserArtPressure) < 120) {
        return 120
      } else if (Number(this.getUserArtPressure) > 180) {
        return 180
      } else {
        return Number(this.getUserArtPressure)
      }
    },
    prepareCholesterol () {
      if (Number(this.getUserCholesterol) < 4) {
        return 4
      } else if (Number(this.getUserCholesterol) > 8) {
        return 8
      } else {
        return Number(this.getUserCholesterol)
      }
    }
  },
  methods: {
    bye: function () {
      const logger = PromobotLogger.getInstance()
      const eventId = logger.logEvent(EventInitiatorTypes.USER, EventTypes.CLICK)
      this.$store.dispatch('engine/handlerClickMoveToState', {
        meta: { eventId },
        data: 'BYE'
      })
    },
    changeIbs: function (type, change) {
      if (this.userData[type] + change >= 0 && this.userData[type] + change < this.table[type].length) {
        // const logger = PromobotLogger.getInstance()
        // const eventId = logger.logEvent(EventInitiatorTypes.USER, EventTypes.CLICK)
        if (type === 0) {
          // console.warn('Diff ad', this.table[type][this.userData[type] + change])
          this.resultTableData.pressure = this.table[type][this.userData[type] + change]
          // this.$store.dispatch('ui/setUserArtPressure', {
          //   meta: { eventId },
          //   data: this.table[type][this.userData[type] + change]
          // })
        } else if (type === 1) {
          // console.warn('Diff cholesterol', this.table[type][this.userData[type] + change])
          this.resultTableData.cholesterol = this.table[type][this.userData[type] + change]
          // this.$store.dispatch('ui/setUserCholesterol', {
          //   meta: { eventId },
          //   data: this.table[type][this.userData[type] + change]
          // })
        }
      }
    },
    addActive: function (choosen, m, j) {
      this.resultTableData.pressure = m
      // this.$store.dispatch('ui/setUserArtPressure', {
      //   meta: { eventId },
      //   data: m
      // })
      this.resultTableData.cholesterol = j
      // this.$store.dispatch('ui/setUserCholesterol', {
      //   meta: { eventId },
      //   data: j
      // })
    }
  },
  watch: {
    getStep () {
      if (this.getStep === 'ibsResult') {
        this.resultTableData.age = this.getUserAge
        this.resultTableData.gender = this.getUserGender
        this.resultTableData.growth = this.getUserGrowth
        this.resultTableData.weight = this.getUserWeight
        this.resultTableData.smoke = this.getUserSmoke
        this.resultTableData.pressure = this.preparePressure
        this.resultTableData.cholesterol = this.prepareCholesterol
        this.resultTableData.risk = [ ...this.getIbsRisk ]
      }
    }
  }
}
</script>

