<template>
    <div v-if="showComponent" class="wrapper">
        <div class="content-main content">
                <div class="title">
                    <p>{{title}}</p>
                </div>
                <div class="container">
                    <div class="block">
                        <p class="part">
                            Предлагаем пройти консультацию и получить необходимые рекомендации по Вашему здоровью.
                            В этой части обследования Вы ответите на конкретные вопросы специалиста.
                        </p>
                    </div>
                    <div class="block">
                        <img :src="itemImageSpecialist">
                    </div>
                </div>
                <div class="div-button">
                    <button class="const" v-on:click="start">Пройти <br>консультацию</button>
                </div>
        </div>
<!--
        <div class="content-main content" v-else>
        <p>{{this.length_quest}}</p>
        <p>setQuestionData</p>
            <div class="img-box">
          <img class="img-quest" :src="itemImageQuestion">
            </div>
            <div class="yes-no">
                <button v-on:click="next(1)">Да</button>
                <button v-on:click="next(0)">Нет</button>
            </div>
      </div>
    -->
