  </template>
<script>
import { mapGetters, mapActions } from 'vuex'
import { getTitle } from '../../store/modules/application/specialist'
import { PromobotLogger, EventInitiatorTypes, EventTypes } from 'promobot-logger'
import { GETPATH } from '../../store/controllers/specialist'

export default {
  name: 'quest_new',
  data () {
    return {
      mainShow: true,
      title: ''
    }
  },
  updated () {
    this.title = getTitle(this.getSpecialistNum)
  },
  computed: {
    ...mapGetters('app', [
      'getStep'
    ]),
    ...mapGetters('ui', [
      'getSpecialistNum'
    ]),
    ...mapGetters('engine', [
      'getCurrentStateName'
    ]),
    showComponent () {
      return this.getStep === 'quest_new'
    },
    itemImageSpecialist () {
      return require(`../../assets/specialist/main/${this.getSpecialistNum}.png`)
    }
  },
  methods: {
    ...mapActions('ui', [
      'setSpecialistNum',
      'setStepQuest',
      'setQuest',
      'setPath'
    ]),
    ...mapActions('engine', [
      'handlerClickMoveToState'
    ]),
    start: function () {
      console.log(this.getSpecialistNum)
      let logger = PromobotLogger.getInstance()
      let eventId = logger.logEvent(EventInitiatorTypes.USER, EventTypes.CLICK)
      this.$store.dispatch('engine/handlerClickMoveToState', {
        meta: { eventId },
        data: 'QUEST_NEW_NEW'
      })
      this.$store.dispatch('ui/setStepQuest', {
        meta: { eventId },
        data: 0
      })
      console.log(GETPATH(this.getSpecialistNum))
      this.$store.dispatch('ui/setPath', {
        meta: { eventId },
        data: GETPATH(this.getSpecialistNum)
      })
      switch (this.getSpecialistNum) {
        case 0: {
          this.$store.dispatch('ui/setQuest', {
            meta: { eventId },
            data: 'Часто ли вы испытываете стресс?'
          })
          break
        }
        case 1: {
          this.$store.dispatch('ui/setQuest', {
            meta: { eventId },
            data: 'Беспокоит ли вас онемение конечностей?'
          })
          break
        }
        case 2: {
          this.$store.dispatch('ui/setQuest', {
            meta: { eventId },
            data: 'Беспокоят ли Вас боли или дискомфорт в области живота?'
          })
          break
        }
        case 3: {
          this.$store.dispatch('ui/setQuest', {
            meta: { eventId },
            data: 'Испытываете ли вы болезненность при менструациях*?'
          })
          break
        }
        case 4: {
          this.$store.dispatch('ui/setQuest', {
            meta: { eventId },
            data: 'Испытываете ли вы затруднение при мочеиспускании?'
          })
          break
        }
        case 5: {
          this.$store.dispatch('ui/setQuest', {
            meta: { eventId },
            data: 'Снижался ли ваш вес без видимых причин за последние несколько месяцев?'
          })
          break
        }
        case 6: {
          this.$store.dispatch('ui/setQuest', {
            meta: { eventId },
            data: 'Изменилось ли зрительное восприятие привычных для вас предметов – висящих на стене часов,'
            + 'календарей, картин? Возможно Вы перестали видеть на них какие-то детали или картинка стала размазанной.'
          })
          break
        }
        case 7: {
          this.$store.dispatch('ui/setQuest', {
            meta: { eventId },
            data: 'Бывает ли у вас ощущение усталости голоса, которое сопровождается осиплостью или охриплостью?'
          })
          break
        }
        case 8: {
          this.$store.dispatch('ui/setQuest', {
            meta: { eventId },
            data: 'Изменился ли в последнее время ваш вес'
            + '(снижается, несмотря на хороший аппетит или наоборот растет, несмотря на соблюдение диеты и физические нагрузки)?'
          })
          break
        }
      }
    }
  }
}
