<template>
  <div v-if="getEngineDebug" class="all-states-container">
    <input v-model="filter" type="text">
    <div class="wrapper">
      <table>
        <tr v-for="(state, index) in states" :key="index">
          <td @click="goToState" :title="index + 1">
            <div class="current-state" v-if="state.name === $store.state.engine.current.stateName"><i><b>{{ state.name }}</b></i></div>
            <div v-else>{{ state.name }}</div>
          </td>
        </tr>
      </table>
    </div>
  </div>
</template>

<script>
import { mapGetters } from 'vuex'
import states from '@/store/states'

const rus = 'йцукенгшщзхъфывапролджэячсмитьбю.'.split('')
const eng = 'qwertyuiop[]asdfghjkl;\'zxcvbnm,./'.split('')

export default {
  name: 'all-states',
  data () {
    return {
      st: states,
      filter: ''
    }
  },
  computed: {
    ...mapGetters('engine', [
      'getEngineDebug'
    ]),
    states () {
      if (this.filter) {
        return this.st.filter(el => {
          el = el.name.toLowerCase()

          let correct = ''
          let currentChar = this.filter.charAt(this.filter.length - 1)

          if (rus.indexOf(currentChar) !== -1) {
            this.filter.split('').forEach(char => {
              correct += eng[rus.indexOf(char)]
            })
            return el.indexOf(correct.toLowerCase()) !== -1
          }
          return el.indexOf(this.filter.toLowerCase()) !== -1
        })
      }
      return this.st
    }
  },
  methods: {
    goToState (event) {
      this.$store.dispatch('engine/handlerClickMoveToState', {
        transition: 'FROM-ALL-STATES-COMPONENT',
        data: event.target.innerText
      })
    }
  },
  updated () {
    // global['curst'] = this.$el.getElementsByClassName('current-state')[0]
  }
}
</script>

