<template>
  <div v-if="getEngineDebug" style="z-index:100000;display:none;" class="debugger"
    :class="{'minimized': minimize}"
    @mouseover="changePosition"
  >

    <!--img :src="getFaceRecognizeGeneralFrame" style="width:150px;height:150px;border:1px solid #ccc;"></img-->
    <div style="width:400px;height:240px;border:1px solid #ccc;display:inline-block;"><img src="http://localhost:8070/stream?topic=/facerecognition/image_raw&type=ros_compressed" style="width:100%;height:100%;" /></div>
    <button class="button__minimize" @click="minimize = !minimize">
      <span>{{ minimize ? '+' : '-' }}</span>
    </button>
    <table :class="{'minimized': minimize}">
      <tr v-for="(getter, index) in getters.filter(getter => getter.toString() !== 'getFaceRecognizeGeneralFrame')" :key="index">
        <td>{{ getter.toString() | splitter  }}</td>
        <td @click="copy" title="Click to copy this value in clipboard">
          {{ self[getter] }}
        </td>
      </tr>
    </table>
  </div>
</template>

<script>
import { mapGetters } from 'vuex'
// import Videostream from '@/components/Videostream.vue'

let excludedGetters = [
  'calcPosition',
  'getEngineDebug'
]

export default {
  name: 'debugger',
  data () {
    return {
      getters: [],
      self: null,
      minimize: false
    }
  },
  computed: {
    ...mapGetters('engine', [
      'getCurrentStateName',
      'getEngineDebug'
    ]),
    ...mapGetters('ui', [
      'getUserAge',
      'getUserMet',
      'getUserGender'
    ]),
    ...mapGetters('robot', [
      'getDialogMuteOnStatus',
      'getFaceRecognizeAutotracking',
      'getFaceRecognizeInfo',
      'getFaceRecognizeGeneralId',
      'getFaceRecognizeGeneralSetted',
      'getFaceRecognizeGeneralFrame'
    ]),
    ...mapGetters('faces', [
      'getStateCount',
      'getStateKnown',
      'getStateGeneral',
      'getUserGeneral',
      'getUserLost',
      'getLogicStatesIsPrivate',
      'getLogicAllowOneGeneral'
    ]),
    ...mapGetters('app', [
      'getSessionName',
      'getStep'
    ])
  },
  methods: {
    changePosition () {
      if (this.change) {
        this.position = this.position === 'left'
          ? 'right'
          : 'left'
      }
    },
    copy (event) {
      let textarea = document.createElement('textarea')

      textarea.value = event.target.innerText
      textarea.style.opacity = 0
      textarea.style.width = 0
      textarea.style.height = 0
      textarea.style.position = 'absolute'
      textarea.style.top = 0
      textarea.style.left = 0

      document.body.appendChild(textarea)

      textarea.select()

      let copy = document.execCommand('copy')

      textarea.remove()
      if (copy) {
        (async () => console.info('copyed', await navigator.clipboard.readText()))()
      }
    }
  },
  mounted () {
    this.self = this

    let getters = Object.keys(this._computedWatchers)

    this.getters = getters.filter(key => {
      return excludedGetters.indexOf(key) === -1
    })
  },
  filters: {
    splitter (value) {
      if (value.startsWith('get')) {
        value = value.slice(3)
      }

      value = [].map.call(value, char => {
        if (char === char.toUpperCase()) {
          return ' ' + char
        }
        return char
      }).join('')

      return value
    }
  }
}
</script>

