<template>
  <div v-show="showComponent" class="wrapper">
    <div class="container-meeting" v-if="showComponent && (paramData === null || paramData === 0)">
      <div class="content_block">
        <div class="fact">Вы курите?</div>
        <img v-if="getLoadAppSettings.icons.activeSvg === false" src="dialog-images/consultation/smoke.png" />
        <div v-if="getLoadAppSettings.icons.activeSvg === true" v-html="smokePic"></div>
      </div>
      <div class="button_block" v-if="getLoadAppSettings">
        <button id="gotoIbs" class="btn" @click="gotoIbs" :style="buttonStyle">Нет</button>
        <button class="btn" @click="yesSmoke" :style="buttonStyle">Да</button>
      </div>
    </div>
    <div class="container-meeting" v-if="showComponent && paramData === 1">
      <div class="content_block">
        <div class="fact">Краткосрочные и долгосрочные преимущества отказа от курения</div>
        <p>{{ info }}</p>
        <div class="liner">
          <div v-for="(f, index) in computedGetSmokeFacts" :data-act="f.action" v-bind:key="index" @mouseenter="showInfo(f.result, index, f.name)" :style="{ ...getLoadAppSettings.scalesStyle }">
            <div class="point"><div :style="scalesStyle"></div></div>
            <div class="liner_text" v-text="f.name"></div>
          </div>
        </div>
      </div>
      <div class="button_block" v-if="getLoadAppSettings">
        <button id="gotoIbs" class="btn" @click="gotoIbs" :style="buttonStyle">Продолжить</button>
      </div>
    </div>
  </div>
</template>

<script>
/* eslint-disable vue/no-side-effects-in-computed-properties */

import { mapGetters } from 'vuex'
import { PromobotLogger, EventInitiatorTypes, EventTypes } from 'promobot-logger'

export default {
  name: 'smoke',
  components: {

  },
  data () {
    return {
      info: null,
      actItem: 0,
      timerInfo: null,
      smokePic: false
    }
  },
  watch: {
    getToldSmoke: function (val) {
      let th = this
      let logger = PromobotLogger.getInstance()
      let eventId = logger.logEvent(EventInitiatorTypes.USER, EventTypes.CLICK)
      this.$store.getters['ui/getSmokeFacts'].forEach(function (item, i, arr) {
        if (item.search.includes(val)) {
          th.showInfo(item.result, i, item.name)
          th.$store.dispatch('robot/sendDialogMuteOn', {
            meta: { eventId }
          })
          setTimeout(() => {
            th.$store.dispatch('robot/sendDialogMuteOff', {
              meta: { eventId }
            })
          }, 3000)
        }
      })
    }
  },
  computed: {
    ...mapGetters('app', [
      'getStep',
      'getSessionName',
      'getMeetingTalk',
      'getLoadAppSettings',
      'getIconsSVG'
    ]),
    ...mapGetters('ui', [
      'getSubtitlesEnabled',
      'getImtStep',
      'getUserGrowth',
      'getUserSmoke',
      'getSmokeFacts',
      'getToldSmoke'
    ]),
    ...mapGetters('engine', [
      'getCurrentStateName'
    ]),
    showComponent () {
      if (this.$store.getters['app/getStep'] === 'smoke') {
        this.smokePic = this.getIconsSVG.smoke
        if (this.$store.getters['ui/getUserSmoke'] === null) {
          this.actItem = 0
          this.info = this.$store.getters['ui/getSmokeFacts'][this.actItem].result
        }
      }
      return this.$store.getters['app/getStep'] === 'smoke'
    },
    paramData () {
      return this.$store.getters['ui/getUserSmoke']
    },
    computedGetSmokeFacts () {
      let updGetSmokeFacts = []
      let th = this
      this.$store.getters['ui/getSmokeFacts'].forEach(function (item, i, arr) {
        let obj = { 'name': item.name, 'result': item.result, 'action': false }
        if (i === th.actItem) obj.action = true
        updGetSmokeFacts.push(obj)
      })
      return updGetSmokeFacts
    },
    buttonStyle () {
      return this.getLoadAppSettings ? { ...this.getLoadAppSettings.btnMain } : {
        background: '#2589DE',
        borderColor: '#2589DE'
      }
    },
    scalesStyle () {
      return this.getLoadAppSettings ? { ...this.getLoadAppSettings.scalesStyle } : {
        color: '#2589DE',
        backgroundColor: '#2589DE'
      }
    }
  },
  methods: {
    gotoIbs: function () {
      let logger = PromobotLogger.getInstance()
      let eventId = logger.logEvent(EventInitiatorTypes.USER, EventTypes.CLICK)
      let actions = []
      actions.push({ 'name': 'ui/setUserSmoke', 'options': 0, 'timeout': 0 })
      actions.push({ 'name': 'ui/setSpinnerEnabled', 'options': true, 'timeout': 0 })
      actions.push({ 'name': 'ui/setMeasurementStep', 'options': 1, 'timeout': 0 })
      actions.push({ 'name': 'ui/setMeasurementNum', 'options': 5, 'timeout': 0 })
      actions.forEach(item => {
        setTimeout(() => {
          this.$store.dispatch(item.name, { meta: { eventId }, data: item.options })
        }, item.timeout)
      })
    },
    yesSmoke: function () {
      let logger = PromobotLogger.getInstance()
      let eventId = logger.logEvent(EventInitiatorTypes.USER, EventTypes.CLICK)
      this.$store.dispatch('ui/setUserSmoke', {
        meta: { eventId },
        data: 1
      })
      this.$store.dispatch('engine/handlerClickMoveToState', {
        meta: { eventId },
        data: 'SMOKE-1'
      })
    },
    showInfo: function (value, i, after) {
      this.info = value
      this.actItem = i
      clearTimeout(this.timerInfo)
      this.timerInfo = setTimeout(() => {
        let logger = PromobotLogger.getInstance()
        let eventId = logger.logEvent(EventInitiatorTypes.USER, EventTypes.CLICK)
        this.$store.dispatch('robot/abortRobotReplic', {
          meta: { eventId }
        })
        this.$store.dispatch('robot/sayText', {
          meta: { eventId },
          data: 'Через ' + after + ' ' + value
        })
      }, 200)
    }
  }
}
</script>

