<template>
  <div v-show="showComponent" class="wrapper">
    <div class="container-meeting" v-show="showComponent">
      <div class="content_block">
        <div class="fact">Спасибо Вам за прохождение консультации!<br />Распечатать результат проведенного опроса?</div>
        <div class="result_block">
          <div v-for="(f, index) in computedResult" v-bind:key="index" @click="sayText(f.id)">
            <div class="img_div"><img :src="imgAddress(f.image)" /></div>
            <div class="text_div"><p v-html="f.text"></p></div>
          </div>
        </div>
      </div>
      <div class="button_block" v-if="getLoadAppSettings">
        <button id="printBtn" class="btn" @click="printTalon($event)" :style="buttonStyle">Распечатать результат</button>
        <button class="btn" @click="toState('START_NEW')" :style="buttonStyle">На главную</button>
      </div>
    </div>
  </div>
</template>

<script>
import { mapGetters } from 'vuex'
import { PromobotLogger, EventInitiatorTypes, EventTypes } from 'promobot-logger'
import { getMedResult, inArray, ibsData } from '@/utils'

export default {
  name: 'bye',
  data () {
    return {
      result: [
        { 'id': 1, 'image': 'result-icon-1.png', 'text': 'Обратитесь к врачу', 'active': 'true' },
        { 'id': 2, 'image': 'result-icon-2.png', 'text': 'ИМТ<br />20 - 25', 'active': 'true' },
        { 'id': 3, 'image': 'result-icon-3.png', 'text': 'Бросайте курить', 'active': 'true' },
        { 'id': 4, 'image': 'result-icon-4.png', 'text': 'Холестерин < 4,5 ммоль/л ', 'active': 'true' },
        { 'id': 5, 'image': 'result-icon-5.png', 'text': 'Давление <140/ 90 мм рт.ст.', 'active': 'true' },
        { 'id': 6, 'image': 'result-icon-6.png', 'text': '30 минут в день', 'active': 'true' },
        { 'id': 7, 'image': 'result-icon-7.png', 'text': 'Минимум соли', 'active': 'true' },
        { 'id': 8, 'image': 'result-icon-8.png', 'text': 'Правильное питание', 'active': 'true' },
        { 'id': 9, 'image': 'result-icon-9.png', 'text': 'Внимание к советам', 'active': 'true' }
      ],
      user: { // Тестовый user
        weight: 60,
        growth: 170,
        artPressure: 120,
        cholesterol: 4,
        smoke: 0,
        age: 58,
        gender: 0,
        relativesProblems: 0,
        heartProblems: 0
      },
      templatePath: 'talon-template.html'
    }
  },
  computed: {
    ...mapGetters('app', [
      'getStep',
      'getSessionName',
      'getMeetingTalk',
      'getLoadAppSettings'
    ]),
    ...mapGetters('ui', [
      'getSubtitlesEnabled',
      'getImtStep',
      'getUserGrowth',
      'getUserWeight',
      'getUser',
      'getResultGroup',
      'getResultItems',
      'getIbsRisk',
      'getUserGlucometry',
      'getUserArtPressureLow',
      'getUserPulse',
      'getUserTemperature',
      'getUserArtPressureEnter'
    ]),
    buttonStyle () {
      return this.getLoadAppSettings ? { ...this.getLoadAppSettings.btnMain } : {
        background: '#2589DE',
        borderColor: '#2589DE'
      }
    },
    showComponent () {
      if (this.$store.getters['app/getStep'] === 'bye') {
        document.getElementById('printBtn').removeAttribute('disabled')
      }
      return this.$store.getters['app/getStep'] === 'bye'
    },
    // eslint-disable-next-line vue/return-in-computed-property
    computedResult () {
      if (this.$store.getters['app/getStep'] === 'bye') {
        let user = {
          age: Number(this.$store.getters['ui/getUser'].age),
          artPressure: Number((this.$store.getters['ui/getUser'].artPressureEnter !== null) ? this.$store.getters['ui/getUser'].artPressureEnter : this.$store.getters['ui/getUser'].artPressure),
          cholesterol: Number((this.$store.getters['ui/getUser'].cholesterolEnter !== null) ? this.$store.getters['ui/getUser'].cholesterolEnter : this.$store.getters['ui/getUser'].cholesterol),
          gender: Number(this.$store.getters['ui/getUser'].gender),
          growth: Number(this.$store.getters['ui/getUser'].growth),
          heartProblems: Number(this.$store.getters['ui/getUser'].heartProblems || 0),
          met: Number(this.$store.getters['ui/getUser'].met),
          name: this.$store.getters['ui/getUser'].name,
          relativesProblems: Number(this.$store.getters['ui/getUser'].relativesProblems),
          smoke: Number(this.$store.getters['ui/getUser'].smoke),
          weight: Number(this.$store.getters['ui/getUser'].weight)
        }
        // console.log('getMedResult', getMedResult(user))
        let ar = this.$store.getters['ui/getResultGroup'][getMedResult(user) - 1].sovets
        // let ar = this.$store.getters['ui/getResultGroup'][getMedResult(this.user)].sovets
        let nowResult = []
        this.$store.getters['ui/getResultItems'].forEach(function (item, i, arr) {
          if (inArray(item.id, ar) && (item.id !== 3 || (item.id === 3 && user.smoke === 1))) nowResult.push(item)
        })
        return nowResult
      }
    }
  },
  methods: {
    toState (state) {
      let logger = PromobotLogger.getInstance()
      let eventId = logger.logEvent(EventInitiatorTypes.USER, EventTypes.CLICK)
      this.$store.dispatch('engine/handlerClickMoveToState', {
        meta: { eventId },
        data: state
      })
    },
    printTalon (event) {
      event.target.setAttribute('disabled', 'disabled')
      fetch(this.templatePath).then(response => {
        return response.text()
      }).then(talon => {
        let htmlConclusion = ''
        htmlConclusion += (this.getUserGrowth !== null ? '<p>Рост: ' + this.getUserGrowth + ' см</p>' : '')
        htmlConclusion += (this.getUserWeight !== null ? '<p>Вес: ' + this.getUserWeight + ' кг</p>' : '')
        htmlConclusion += ((typeof this.getUserGlucometry !== 'undefined' && this.getUserGlucometry !== null) ? '<p>Глюкоза: ' + this.getUserGlucometry + ' ммоль/л</p>' : '')
        htmlConclusion += '<p>Давление: ' + ((typeof this.getUserArtPressureEnter !== 'undefined' && this.getUserArtPressureEnter !== null) ? this.getUserArtPressureEnter : '---') + '/' + ((typeof this.getUserArtPressureEnter !== 'undefined' && this.getUserArtPressureEnter !== null) ? this.getUserArtPressureLow : '---') + ' мм.рт.ст.</p>'
        htmlConclusion += ((typeof this.getUserPulse !== 'undefined' && this.getUserPulse !== null) ? '<p>Пульс: ' + this.getUserPulse + ' уд./мин.</p>' : '')
        htmlConclusion += ((typeof this.getUserTemperature !== 'undefined' && this.getUserTemperature !== null) ? '<p>Температура: ' + this.getUserTemperature + ' &deg;C</p>' : '')
        htmlConclusion += '<br />'
        let html = ''
        this.computedResult.forEach(function (item, i, arr) {
          html += '<p>' + (i + 1) + '. ' + item.full_text + '</p>'
          if (item.id === 1) html += '<p>Кроме того:</p>'
        })
        let user = this.$store.getters['ui/getUser']
        user.weight = Number(user.weight)
        user.growth = Number(user.growth)
        user.smoke = Number(user.smoke)
        user.age = Number(user.age)
        user.gender = Number(user.gender)
        user.relativesProblems = Number(user.relativesProblems)
        user.heartProblems = 0

        // console.warn('====age', user.age)
        // console.log('====gender', user.gender)
        // console.log('====weight', user.weight)
        // console.log('====growth', user.growth)
        // console.log('====relativesProblems', user.relativesProblems)
        // console.log('====artPressureEnter', user.artPressureEnter)
        // console.log('====cholesterolEnter', user.cholesterolEnter)
        // console.log('====artPressure', user.artPressure)
        // console.log('====cholesterol', user.cholesterol)

        // let user = this.user // тестовый юзер
        let p = (user.artPressureEnter !== null) ? Number(user.artPressureEnter) : Number(user.artPressure)
        let c = (user.cholesterolEnter !== null) ? Number(user.cholesterolEnter) : Number(user.cholesterol)
        let ibs = ibsData(user.gender, user.age, p, user.smoke, c)
        // let ibs = ibsData(this.user.gender, this.user.age, p, this.user.smoke, c)
        let result = htmlConclusion
        let realImt = Math.round(user.weight / (user.growth * user.growth / (100 * 100)))
        this.$store.getters['ui/getIbsRisk'].forEach(function (item, i, arr) {
          if (ibs >= item.start && ibs < item.stop) result += item.check_text
        })
        if (p < 140 && c < 7 && user.smoke === 0 && realImt < 30) {
          this.$store.getters['ui/getIbsRisk'].forEach(function (item, i, arr) {
            if (ibs >= item.start && ibs < item.stop) result += item.check_text_1
          })
        } else {
          let resultAbnormal = ''
          if (c >= 7) resultAbnormal += ', повышение уровня общего холестерина'
          if (p >= 140) resultAbnormal += ', повышение уровня артериального давления'
          if (realImt >= 30) resultAbnormal += ', повышенный ИМТ'
          if (user.smoke === 1) resultAbnormal += ', курение'
          result += '<p>Однако, так как у Вас есть важный фактор риска – ' + resultAbnormal.substr(2) + ' – и это делает Ваш риск сердечно-сосудистых заболеваний ПОТЕНЦИАЛЬНО ВЫСОКИМ.</p><br />'
        }
        let data = {
          advices: html,
          result: result
        }
        let transFats = false
        for (let k in data) {
          if (data.hasOwnProperty(k)) {
            if (typeof data[k] !== 'undefined') {
              // talon = talon.replace(`{${k}}`, data[k].replace(/\/n/g, '<br>'))
              talon = talon.replace(`{${k}}`, data[k])
              if (data[k].indexOf('транс-жир') > 0) transFats = true
            } else {
              // console.log('====data[k]', k)
            }
          }
        }
        if (transFats) {
          let htmlTransFats = '<br /><p>* Продукты, содержащие транс-жиры</p><p>1) Большинство видов фаст-фуда: выпечка, пироги, печенье, панированные или обжаренные курица и морепродукты, картошка-фри</p><p>2) Готовый попкорн (в том числе, приготовленный в микроволновке)</p><p>3) Замороженная пицца, пироги, блинчики, чебуреки и любые готовые к использованию замороженные полуфабрикаты</p><p>4) "Мягкие" масла, и кулинарный маргарин</p><p>5) Сливки для кофе</p><p>6) Охлаждённые изделия из теста</p><p>7) Фабрично приготовленные десерты, торты, сладости с бисквитным тестом или любым жиром</p>'
          talon = talon.replace('{transFats}', htmlTransFats)
        } else {
          talon = talon.replace('{transFats}', '')
        }
        // console.warn('TALON', talon)
        let logger = PromobotLogger.getInstance()
        let eventId = logger.logEvent(EventInitiatorTypes.USER, EventTypes.CLICK)
        this.$store.dispatch('robot/setPrinterData', {
          meta: { eventId },
          data: {
            mimeType: 'text/html',
            talon
          }
        })
      })
    },
    sayText: function (id) {
      let th = this
      this.$store.getters['ui/getResultItems'].forEach(function (item, i, arr) {
        if (item.id === id) {
          let logger = PromobotLogger.getInstance()
          let eventId = logger.logEvent(EventInitiatorTypes.USER, EventTypes.CLICK)
          th.$store.dispatch('robot/abortRobotReplic', {
            meta: { eventId }
          })
          th.$store.dispatch('robot/sayText', {
            meta: { eventId },
            data: item.say_text
          })
        }
      })
    },
    imgAddress: function (alias) {
      return 'dialog-images/' + alias
    }
  }
}
</script>

