  question[1] = 'Замечаете ли Вы, что теряется острота зрения, цветность, контрастность?'
  question[2] = 'Не появляются ли в поле вашего зрения какие-то пятна (темные, серые) или эффекты (зигзаги, молнии, вспышки)?'
