<template>
  <div class="container-meeting" v-if="showComponent">
    <h2>{{ getImtPhrase }}</h2>
    <div class="content-photo">
      <img v-if="getLoadAppSettings.icons.activeSvg === false" class="svg_pic" :src="getImtImg_png" alt="" title="" />
      <div v-if="getLoadAppSettings.icons.activeSvg === true" class="svg_pic" v-html="getImtImg"></div>
    </div>
    <div class="name_input" :style="meetingInputStyle">
      <button :class="['btn_talk', getMeetingTalk === true ? 'btn_talk_stop' : 'btn_talk_start']" @click="setTalk" />
      <div id="autoclick_clearInput" class="clear" @click="clearInput()">
        <div :style="clearInputStyle"/>
        <div :style="clearInputStyle"/>
      </div>
      <input type="tel" id="meeting_input" v-model.trim="name" autocomplete="off" placeholder="Введите значение" />
      <button class="go_btn" @click="changeImtStep" :disabled="disbledBtn" v-html="nextPic">
        <!--img src="../../assets/img/go-whatsapp.svg" /-->
      </button>
    </div>
  </div>
</template>

<script>
import { mapGetters, mapActions } from 'vuex'
import { PromobotLogger, EventInitiatorTypes, EventTypes } from 'promobot-logger'

export default {
  name: 'imt',
  components: {

  },
  data () {
    return {
      nextPic: false
    }
  },
  computed: {
    disbledBtn () {
      return !this.name
    },
    meetingInputStyle () {
      return this.getLoadAppSettings ? { ...this.getLoadAppSettings.inputMeeting } : {}
    },
    clearInputStyle () {
      return this.getLoadAppSettings ? { ...this.getLoadAppSettings.iconClearUserParam } : { backgroundColor: '#2589DE' }
    },
    // eslint-disable-next-line vue/return-in-computed-property
    computedMistake () {
      let mistake = true
      if (this.$store.getters['ui/getImtStep'] === 0 && this.$store.getters['ui/getUserGrowth'] >= 70 && this.$store.getters['ui/getUserGrowth'] <= 250) mistake = false
      if (this.$store.getters['ui/getImtStep'] === 1 && this.$store.getters['ui/getUserGrowth'] >= 20 && this.$store.getters['ui/getUserGrowth'] <= 250) mistake = false
      let logger = PromobotLogger.getInstance()
      let eventId = logger.logEvent(EventInitiatorTypes.USER, EventTypes.CLICK)
      this.$store.dispatch('ui/setImtMistake', {
        meta: { eventId },
        data: mistake
      })
    },
    name: {
      // eslint-disable-next-line vue/return-in-computed-property
      get () {
        if (this.getImtStep === 0) return this.$store.getters['ui/getUserGrowth']
        if (this.getImtStep === 1) return this.$store.getters['ui/getUserWeight']
      },
      set (value) {
        let logger = PromobotLogger.getInstance()
        let eventId = logger.logEvent(EventInitiatorTypes.USER, EventTypes.KEYUP)
        let action = 'ui/setUserGrowth'
        if (this.$store.getters['ui/getImtStep'] === 1) action = 'ui/setUserWeight'
        this.$store.dispatch(action, {
          meta: { eventId },
          data: value
        })
        // eslint-disable-next-line no-unused-expressions
        this.computedMistake
      }
    },
    ...mapGetters('app', [
      'getStep',
      'getSessionName',
      'getMeetingTalk',
      'getLoadAppSettings',
      'getIconsSVG'
    ]),
    ...mapGetters('ui', [
      'getSubtitlesEnabled',
      'getImtStep',
      'getUserWeight',
      'getUserGrowth'
    ]),
    ...mapGetters('robot', [
      'getFaceRecognizeGeneralFrame',
      'getRobotDialogUserActionActive'
    ]),
    ...mapGetters('engine', [
      'getCurrentStateName'
    ]),
    showComponent () {
      let logger = PromobotLogger.getInstance()
      let eventId = logger.logEvent(EventInitiatorTypes.USER, EventTypes.CLICK)
      if (this.getStep === 'imt') {
        // eslint-disable-next-line vue/no-side-effects-in-computed-properties
        this.nextPic = this.getIconsSVG.next
        if (this.$store.getters['ui/getImtStep'] === null || this.$store.getters['ui/getImtStep'] === 0) {
          this.$store.dispatch('ui/setImtStep', {
            meta: { eventId },
            data: 0
          })
          this.$store.dispatch('ui/setHeaderBtnLeftEnabled', {
            meta: { eventId },
            data: true
          })
          this.$store.dispatch('ui/setHeaderBtnLeftAction', {
            meta: { eventId },
            data: { 'ui/setImtStep': 0, 'engine/handlerMoveToState': 'START_NEW' }
          })
        } else if (this.$store.getters['ui/getImtStep'] === 1) {
          this.$store.dispatch('ui/setHeaderBtnLeftAction', {
            meta: { eventId },
            data: { 'ui/setImtStep': 0, 'engine/handlerMoveToState': 'IMT' }
          })
          this.$store.dispatch('ui/setHeaderBtnLeftEnabled', {
            meta: { eventId },
            data: true
          })
        }
        // eslint-disable-next-line vue/no-async-in-computed-properties
        setTimeout(() => {
          if (document.getElementById('meeting_input')) {
            document.getElementById('meeting_input').focus()
          }
        }, 100)
      }
      return this.getStep === 'imt'
    },
    // eslint-disable-next-line vue/return-in-computed-property
    getImtPhrase () {
      if (this.getImtStep === 0) return 'Какой у Вас рост (см)?'
      if (this.getImtStep === 1) return 'Какой у Вас вес (кг)?'
    },
    // eslint-disable-next-line vue/return-in-computed-property
    getImtImg () {
      if (this.getImtStep === 0) return this.getIconsSVG.height
      if (this.getImtStep === 1) return this.getIconsSVG.weight
    },
    // eslint-disable-next-line vue/return-in-computed-property
    getImtImg_png () {
      if (this.getImtStep === 0) return 'dialog-images/consultation/height.png'
      if (this.getImtStep === 1) return 'dialog-images/consultation/weight-scale.png'
    }
  },
  methods: {
    ...mapActions('engine', [
      'handlerClickMoveToState'
    ]),
    ...mapActions('ui', [
      'setUserGrowth',
      'setUserWeight',
      'setHeaderBtnLeftAction',
      'setImtStep'
    ]),
    ...mapActions('robot', [
      'abortRobotReplic'
    ]),
    clearInput: function () {
      let logger = PromobotLogger.getInstance()
      let eventId = logger.logEvent(EventInitiatorTypes.USER, EventTypes.CLICK)
      let action = 'ui/setUserGrowth'
      if (this.$store.getters['ui/getImtStep'] === 1) action = 'ui/setUserWeight'
      this.$store.dispatch(action, {
        meta: { eventId },
        data: ''
      })
      setTimeout(() => {
        if (document.getElementById('meeting_input')) {
          document.getElementById('meeting_input').focus()
        }
      }, 100)
    },
    setTalk () {
      let logger = PromobotLogger.getInstance()
      let eventId = logger.logEvent(EventInitiatorTypes.USER, EventTypes.CLICK, {
        transition: 'CHANGE-TALK'
      })
      this.abortRobotReplic()
      this.$store.dispatch('app/setMeetingTalk', {
        meta: { eventId },
        data: !this.getMeetingTalk
      })
    },
    changeImtStep (e) {
      let logger = PromobotLogger.getInstance()
      let eventId = logger.logEvent(EventInitiatorTypes.USER, EventTypes.CLICK)
      if (this.$store.getters['engine/getCurrentStateName'] === 'IMT-S') {
        if (this.$store.getters['ui/getUserGrowth'] >= 70 && this.$store.getters['ui/getUserGrowth'] <= 250) {
          this.$store.dispatch('engine/handlerMoveToState', {
            meta: { eventId },
            data: 'MEASUREMENT_4_4'
          })
        } else {
          this.$store.dispatch('engine/handlerMoveToState', {
            meta: { eventId },
            data: 'IMT-MISTAKE-S'
          })
        }
      } else {
        if (this.$store.getters['ui/getImtStep'] === 0) {
          if (this.$store.getters['ui/getUserGrowth'] >= 70 && this.$store.getters['ui/getUserGrowth'] <= 250) {
            this.$store.dispatch('engine/handlerMoveToState', {
              meta: { eventId },
              data: 'IMT-1'
            })
            this.$store.dispatch('ui/setImtStep', {
              meta: { eventId },
              data: this.$store.getters['ui/getImtStep'] + 1
            })
          } else {
            this.$store.dispatch('engine/handlerMoveToState', {
              meta: { eventId },
              data: 'IMT-MISTAKE'
            })
          }
        } else if (this.$store.getters['ui/getImtStep'] === 1) {
          if (this.$store.getters['ui/getUserWeight'] >= 20 && this.$store.getters['ui/getUserWeight'] <= 250) {
            let lc = JSON.parse(localStorage.getItem('med_' + String(this.$store.getters['faces/getUserGeneral'].id))) || {}
            let forwardActionsLocalStorage = []
            let date = new Date()
            forwardActionsLocalStorage.push({ 'name': 'ui/setUserWeight', 'options': this.$store.getters['ui/getUserWeight'], 'type': 'manual', 'date': date.getUTCFullYear() + '/' + (date.getUTCMonth() + 1) + '/' + date.getUTCDate() + '_' + date.getHours() + ':' + date.getMinutes() + ':' + date.getSeconds() })
            forwardActionsLocalStorage.push({ 'name': 'ui/setUserGrowth', 'options': this.$store.getters['ui/getUserGrowth'], 'type': 'manual', 'date': date.getUTCFullYear() + '/' + (date.getUTCMonth() + 1) + '/' + date.getUTCDate() + '_' + date.getHours() + ':' + date.getMinutes() + ':' + date.getSeconds() })
            lc[3] = forwardActionsLocalStorage
            localStorage.setItem('med_' + String(this.$store.getters['faces/getUserGeneral'].id), JSON.stringify(lc))
            this.$store.dispatch('engine/handlerMoveToState', {
              meta: { eventId },
              data: 'IMT-SUCCESS'
            })
          } else {
            this.$store.dispatch('engine/handlerMoveToState', {
              meta: { eventId },
              data: 'IMT-MISTAKE-1'
            })
          }
        }
      }
    }
  }
}
</script>

